namespace sv_c1a16aab37b648cda1cb2de94c76bc26.Services;

public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private static readonly Random _random = new();

    private static readonly (string Title, string Message, Severity Severity)[] _templates =
    [
        ("CPU Spike", "CPU usage exceeded 90% on server-web-03.", Severity.Critical),
        ("Disk Space Low", "Server db-01 has less than 10% disk space remaining.", Severity.Warning),
        ("Deployment Complete", "Version 2.4.1 deployed successfully to production.", Severity.Info),
        ("Memory Alert", "Memory usage on app-server-02 is at 85%.", Severity.Warning),
        ("Service Down", "Payment gateway is not responding.", Severity.Critical),
        ("Backup Finished", "Nightly backup completed for all databases.", Severity.Info),
        ("SSL Expiry", "Certificate for api.example.com expires in 7 days.", Severity.Warning),
        ("New User Signup", "100 new users registered in the last hour.", Severity.Info),
        ("Rate Limit Hit", "API rate limit exceeded for client app-mobile.", Severity.Critical),
        ("Health Check OK", "All services passed health check.", Severity.Info),
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_timer is not null) return;

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        _ = RunAsync(_cts.Token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _timer = null;
        _cts?.Dispose();
        _cts = null;
    }

    private async Task RunAsync(CancellationToken cancellationToken)
    {
        while (await _timer!.WaitForNextTickAsync(cancellationToken).ConfigureAwait(false))
        {
            var template = _templates[_random.Next(_templates.Length)];
            _hub.AddNotification(template.Title, template.Message, template.Severity);
        }
    }

    public void Dispose()
    {
        Stop();
    }
}

