@using sv_c1a16aab37b648cda1cb2de94c76bc26.Services
@implements IDisposable
@inject NotificationHub Hub

<a href="notifications" class="nav-link notification-bell" title="Notifications">
    <span class="bi bi-bell-fill-nav-menu" aria-hidden="true"></span>
    Notifications
    @if (_unreadCount > 0)
    {
        <span class="badge bg-danger rounded-pill ms-1">@_unreadCount</span>
    }
</a>

@code {
    private int _unreadCount;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        Hub.OnChange += HandleStateChanged;
    }

    private void HandleStateChanged()
    {
        InvokeAsync(() =>
        {
            _unreadCount = Hub.GetUnreadCount();
            StateHasChanged();
        });
    }

    public void Dispose()
    {
        Hub.OnChange -= HandleStateChanged;
    }
}

::deep .notification-bell {
    position: relative;
    display: flex;
    align-items: center;
    gap: 0.25rem;
}

::deep .notification-bell .badge {
    font-size: 0.65rem;
    min-width: 1.2rem;
    padding: 0.2em 0.4em;
}

@page "/notifications"
@using sv_c1a16aab37b648cda1cb2de94c76bc26.Services
@implements IDisposable
@inject NotificationHub Hub
@rendermode InteractiveServer

<PageTitle>Notifications</PageTitle>

<h3>Notifications</h3>

<div class="mb-3">
    <button class="btn btn-outline-primary btn-sm" @onclick="MarkAllRead" disabled="@(_unreadCount == 0)">
        Mark All Read
    </button>
    <span class="ms-2 text-muted">@_unreadCount unread</span>
</div>

@if (!_notifications.Any())
{
    <p class="text-muted">No notifications.</p>
}
else
{
    @foreach (var group in _notifications.GroupBy(n => n.Severity).OrderBy(g => g.Key))
    {
        <h5 class="mt-4">
            <span class="badge @GetSeverityBadgeClass(group.Key)">@group.Key</span>
        </h5>
        <div class="list-group mb-3">
            @foreach (var notification in group.OrderByDescending(n => n.Timestamp))
            {
                <div class="list-group-item @(notification.IsRead ? "" : "list-group-item-light fw-bold")">
                    <div class="d-flex justify-content-between align-items-start">
                        <div>
                            <h6 class="mb-1">@notification.Title</h6>
                            <p class="mb-1 small">@notification.Message</p>
                            <small class="text-muted">@notification.Timestamp.ToString("g")</small>
                        </div>
                        <div class="btn-group btn-group-sm">
                            @if (!notification.IsRead)
                            {
                                <button class="btn btn-outline-success" @onclick="() => MarkRead(notification.Id)">
                                    Mark Read
                                </button>
                            }
                            <button class="btn btn-outline-danger" @onclick="() => Dismiss(notification.Id)">
                                Dismiss
                            </button>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    private IReadOnlyList<Notification> _notifications = [];
    private int _unreadCount;

    protected override void OnInitialized()
    {
        LoadState();
        Hub.OnChange += HandleStateChanged;
    }

    private void LoadState()
    {
        _notifications = Hub.Notifications;
        _unreadCount = Hub.GetUnreadCount();
    }

    private void MarkRead(Guid id) => Hub.MarkAsRead(id);

    private void MarkAllRead() => Hub.MarkAllRead();

    private void Dismiss(Guid id) => Hub.DismissNotification(id);

    private void HandleStateChanged()
    {
        InvokeAsync(() =>
        {
            LoadState();
            StateHasChanged();
        });
    }

    private static string GetSeverityBadgeClass(Severity severity) => severity switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning => "bg-warning text-dark",
        _ => "bg-info text-dark"
    };

    public void Dispose()
    {
        Hub.OnChange -= HandleStateChanged;
    }
}

