+@using sv_c1a16aab37b648cda1cb2de94c76bc26.Services
+@implements IDisposable
+@inject NotificationHub Hub
+
+<h5>Recent Unread</h5>
+
+@if (!_recentUnread.Any())
+{
+    <p class="text-muted small">No unread notifications.</p>
+}
+else
+{
+    <div class="list-group list-group-flush">
+        @foreach (var notification in _recentUnread)
+        {
+            <div class="list-group-item d-flex justify-content-between align-items-center px-0">
+                <div>
+                    <span class="badge @GetSeverityBadgeClass(notification.Severity) me-1">@notification.Severity</span>
+                    <strong>@notification.Title</strong>
+                    <br />
+                    <small class="text-muted">@notification.Message</small>
+                </div>
+                <button class="btn btn-sm btn-outline-danger" @onclick="() => Dismiss(notification.Id)">
+                    Dismiss
+                </button>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private List<Notification> _recentUnread = new();
+
+    protected override void OnInitialized()
+    {
+        LoadState();
+        Hub.OnChange += HandleStateChanged;
+    }
+
+    private void LoadState()
+    {
+        _recentUnread = Hub.Notifications
+            .Where(n => !n.IsRead)
+            .OrderByDescending(n => n.Timestamp)
+            .Take(3)
+            .ToList();
+    }
+
+    private void Dismiss(Guid id) => Hub.DismissNotification(id);
+
+    private void HandleStateChanged()
+    {
+        InvokeAsync(() =>
+        {
+            LoadState();
+            StateHasChanged();
+        });
+    }
+
+    private static string GetSeverityBadgeClass(Severity severity) => severity switch
+    {
+        Severity.Critical => "bg-danger",
+        Severity.Warning => "bg-warning text-dark",
+        _ => "bg-info text-dark"
+    };
+
+    public void Dispose()
+    {
+        Hub.OnChange -= HandleStateChanged;
+    }
+}
+

