@page "/dashboard"
@using sv_c1a16aab37b648cda1cb2de94c76bc26.Services
@implements IDisposable
@inject SimulatorService Simulator
@rendermode InteractiveServer

<PageTitle>Dashboard</PageTitle>

<h3>Dashboard</h3>

<div class="row">
    <div class="col-md-6">
        <div class="card">
            <div class="card-header">Notification Summary</div>
            <div class="card-body">
                <NotificationSummaryPanel />
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <p class="text-muted">
                    A random notification is generated every 15 seconds to simulate server-push events.
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        Simulator.Start();
    }

    public void Dispose()
    {
        Simulator.Stop();
    }
}

